INSERT INTO public.drills (id, title, category, description, pdf_url, video_url, created_at)
VALUES
('86e49480-54e6-42e1-8cf4-06b76ef5c75d', 'Gate Drill Centre Strike  3 ft (L to R)', 'Putting', 'Find the Line: Locate a small breaking Left to Right 3-foot putt on the green to ensure zero break.
Anchor the Putter: Place your putter head behind the ball as if you are ready to stroke it.
Set the Gate: Insert two tees into the ground—one just outside the toe and one just outside the heel of the putter.
Adjust Clearance: Start with about 0.5cm of space on either side of the putter head.
The Test: Ensure the putter can pass through the "gate" without clicking the tees; as you improve, narrow the gap to increase the difficulty.', NULL, NULL, '2026-03-01T03:50:52.526Z'),
('303b4531-7147-4e7c-8f0a-098c18aebb0b', 'Gate Drill Centre Strike  3 ft Straight', 'Putting', 'Find the Line: Locate a dead-flat 3-foot putt on the green to ensure zero break.
Anchor the Putter: Place your putter head behind the ball as if you are ready to stroke it.
Set the Gate: Insert two tees into the ground—one just outside the toe and one just outside the heel of the putter.
Adjust Clearance: Start with about 0.5cm of space on either side of the putter head.
The Test: Ensure the putter can pass through the "gate" without clicking the tees; as you improve, narrow the gap to increase the difficulty.', NULL, NULL, '2026-03-01T03:50:52.527Z'),
('934c2514-bd5f-4b6f-8710-4a789e90ae05', 'Gate Drill Centre Strike  3 ft (R to L)', 'Putting', 'Find the Line: Locate a small breaking Right to Left 3-foot putt on the green to ensure zero break.
Anchor the Putter: Place your putter head behind the ball as if you are ready to stroke it.
Set the Gate: Insert two tees into the ground—one just outside the toe and one just outside the heel of the putter.
Adjust Clearance: Start with about 0.5cm of space on either side of the putter head.
The Test: Ensure the putter can pass through the "gate" without clicking the tees; as you improve, narrow the gap to increase the difficulty.', NULL, NULL, '2026-03-01T03:50:52.527Z'),
('1b95bc30-b6e4-429f-8b8a-9f66a7c02333', 'Gate Drill Start Line 3 ft (L to R)', 'Putting', 'Find a 3ft small breaking Left to Right Putt. Set two tees 3 inches in front of the ball, just wider than the ball’s diameter. Goal: Roll the ball through the "start gate" without touching the tees. Focus on a square face at impact to ensure the ball starts on the intended line.', NULL, NULL, '2026-03-01T03:50:52.527Z'),
('fd021b02-7ca7-4755-889d-61a871e0ffc9', 'Gate Drill Start Line 3 ft Straight', 'Putting', 'Find a 3ft straight putt. Set two tees 3 inches in front of the ball, just wider than the ball’s diameter. Goal: Roll the ball through the "start gate" without touching the tees. Focus on a square face at impact to ensure the ball starts on the intended line.', NULL, NULL, '2026-03-01T03:50:52.527Z'),
('56cdf675-ab97-4329-876b-5ca5568c1722', 'Gate Drill Start Line 3 ft (R to L)', 'Putting', 'Find a 3ft  small breaking Right to Left Putt. Set two tees 3 inches in front of the ball, just wider than the ball’s diameter. Goal: Roll the ball through the "start gate" without touching the tees. Focus on a square face at impact to ensure the ball starts on the intended line.', NULL, NULL, '2026-03-01T03:50:52.527Z'),
